  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// =====================\n// ENUMS\n// =====================\n\nenum RoleName {\n  SUPER_ADMIN\n  OWNER\n  DIRECTOR\n  ACADEMIC_OFFICE\n  MODERATOR\n  TEACHER\n  STUDENT\n}\n\nenum AdmissionStatus {\n  PENDING\n  APPROVED\n  REJECTED\n}\n\nenum AttendanceStatus {\n  PRESENT\n  ABSENT\n  LATE\n  EXCUSED\n}\n\n// =====================\n// USER & ROLE\n// =====================\n\nmodel User {\n  id        Int      @id @default(autoincrement())\n  email     String   @unique\n  password  String\n  firstName String\n  lastName  String\n  phone     String?\n  avatarUrl String?\n  isActive  Boolean  @default(true)\n  roleId    Int\n  role      Role     @relation(fields: [roleId], references: [id])\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  teacherClasses   ClassGroup[]       @relation(\"TeacherClasses\")\n  enrollments      Enrollment[]\n  attendancesTaken Attendance[]       @relation(\"AttendanceTaker\")\n  attendances      Attendance[]       @relation(\"StudentAttendance\")\n  gradesGiven      Grade[]            @relation(\"GradeGiver\")\n  gradesReceived   Grade[]            @relation(\"StudentGrade\")\n  materials        Material[]\n  newsPosts        News[]\n  admissionReviews AdmissionRequest[] @relation(\"ReviewedBy\")\n  contactReplies   ContactMessage[]   @relation(\"RepliedBy\")\n  logs             SystemLog[]\n\n  @@map(\"users\")\n}\n\nmodel Role {\n  id    Int      @id @default(autoincrement())\n  name  RoleName @unique\n  users User[]\n\n  @@map(\"roles\")\n}\n\n// =====================\n// PROGRAM & CLASS\n// =====================\n\nmodel Program {\n  id          Int      @id @default(autoincrement())\n  name        String   @unique\n  description String?  @db.Text\n  isActive    Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  classes    ClassGroup[]\n  admissions AdmissionRequest[]\n\n  @@map(\"programs\")\n}\n\nmodel ClassGroup {\n  id        Int       @id @default(autoincrement())\n  name      String\n  programId Int\n  program   Program   @relation(fields: [programId], references: [id])\n  teacherId Int?\n  teacher   User?     @relation(\"TeacherClasses\", fields: [teacherId], references: [id])\n  startDate DateTime?\n  endDate   DateTime?\n  isActive  Boolean   @default(true)\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n\n  schedules   Schedule[]\n  enrollments Enrollment[]\n  attendances Attendance[]\n  grades      Grade[]\n  materials   Material[]\n\n  @@map(\"class_groups\")\n}\n\nmodel Schedule {\n  id           Int        @id @default(autoincrement())\n  classGroupId Int\n  classGroup   ClassGroup @relation(fields: [classGroupId], references: [id])\n  dayOfWeek    Int\n  startTime    String\n  endTime      String\n  room         String?\n\n  @@map(\"schedules\")\n}\n\n// =====================\n// ENROLLMENT\n// =====================\n\nmodel Enrollment {\n  id           Int        @id @default(autoincrement())\n  studentId    Int\n  student      User       @relation(fields: [studentId], references: [id])\n  classGroupId Int\n  classGroup   ClassGroup @relation(fields: [classGroupId], references: [id])\n  enrolledAt   DateTime   @default(now())\n\n  @@unique([studentId, classGroupId])\n  @@map(\"enrollments\")\n}\n\n// =====================\n// ATTENDANCE & GRADE\n// =====================\n\nmodel Attendance {\n  id           Int              @id @default(autoincrement())\n  classGroupId Int\n  classGroup   ClassGroup       @relation(fields: [classGroupId], references: [id])\n  studentId    Int\n  student      User             @relation(\"StudentAttendance\", fields: [studentId], references: [id])\n  date         DateTime\n  status       AttendanceStatus @default(PRESENT)\n  takenById    Int\n  takenBy      User             @relation(\"AttendanceTaker\", fields: [takenById], references: [id])\n  createdAt    DateTime         @default(now())\n\n  @@unique([classGroupId, studentId, date])\n  @@map(\"attendances\")\n}\n\nmodel Grade {\n  id           Int        @id @default(autoincrement())\n  classGroupId Int\n  classGroup   ClassGroup @relation(fields: [classGroupId], references: [id])\n  studentId    Int\n  student      User       @relation(\"StudentGrade\", fields: [studentId], references: [id])\n  givenById    Int\n  givenBy      User       @relation(\"GradeGiver\", fields: [givenById], references: [id])\n  title        String\n  score        Float\n  maxScore     Float      @default(100)\n  comment      String?    @db.Text\n  createdAt    DateTime   @default(now())\n\n  @@map(\"grades\")\n}\n\n// =====================\n// MATERIALS\n// =====================\n\nmodel Material {\n  id           Int        @id @default(autoincrement())\n  classGroupId Int\n  classGroup   ClassGroup @relation(fields: [classGroupId], references: [id])\n  uploadedById Int\n  uploadedBy   User       @relation(fields: [uploadedById], references: [id])\n  title        String\n  fileUrl      String\n  fileType     String?\n  createdAt    DateTime   @default(now())\n\n  @@map(\"materials\")\n}\n\n// =====================\n// NEWS / ANNOUNCEMENT\n// =====================\n\nmodel News {\n  id          Int      @id @default(autoincrement())\n  title       String\n  content     String   @db.Text\n  imageUrl    String?\n  isPublished Boolean  @default(false)\n  authorId    Int\n  author      User     @relation(fields: [authorId], references: [id])\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  @@map(\"news\")\n}\n\n// =====================\n// ADMISSION\n// =====================\n\nmodel AdmissionRequest {\n  id           Int             @id @default(autoincrement())\n  firstName    String\n  lastName     String\n  email        String\n  phone        String\n  programId    Int\n  program      Program         @relation(fields: [programId], references: [id])\n  message      String?         @db.Text\n  status       AdmissionStatus @default(PENDING)\n  reviewedById Int?\n  reviewedBy   User?           @relation(\"ReviewedBy\", fields: [reviewedById], references: [id])\n  createdAt    DateTime        @default(now())\n  updatedAt    DateTime        @updatedAt\n\n  @@map(\"admission_requests\")\n}\n\n// =====================\n// CONTACT / FEEDBACK\n// =====================\n\nmodel ContactMessage {\n  id          Int      @id @default(autoincrement())\n  name        String\n  email       String\n  subject     String?\n  message     String   @db.Text\n  isReplied   Boolean  @default(false)\n  repliedById Int?\n  repliedBy   User?    @relation(\"RepliedBy\", fields: [repliedById], references: [id])\n  createdAt   DateTime @default(now())\n\n  @@map(\"contact_messages\")\n}\n\n// =====================\n// SYSTEM LOG\n// =====================\n\nmodel SystemLog {\n  id        Int      @id @default(autoincrement())\n  userId    Int?\n  user      User?    @relation(fields: [userId], references: [id])\n  action    String\n  details   String?  @db.Text\n  ipAddress String?\n  createdAt DateTime @default(now())\n\n  @@map(\"system_logs\")\n}\n",
